namespace DocSummary.Models;

public class SummarizeRequest
{
    public required string Text { get; set; }
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public required string Summary { get; set; }
    public int OriginalLength { get; set; }
    public int SummaryLength { get; set; }
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

public interface IDocumentSummarizer
{
    string Summarize(string text, int maxSentences);
}

public partial class DocumentSummarizer : IDocumentSummarizer
{
    public string Summarize(string text, int maxSentences)
    {
        if (string.IsNullOrWhiteSpace(text))
            return string.Empty;

        var sentences = SentenceRegex().Matches(text)
            .Select(m => m.Value.Trim())
            .Where(s => s.Length > 0)
            .ToList();

        if (sentences.Count == 0)
            return text.Trim();

        // Score sentences by word frequency relevance
        var wordFrequency = GetWordFrequency(text);
        var scored = sentences
            .Select(s => new { Sentence = s, Score = ScoreSentence(s, wordFrequency) })
            .OrderByDescending(x => x.Score)
            .Take(maxSentences)
            .ToList();

        // Return sentences in their original order
        var selected = scored
            .OrderBy(x => sentences.IndexOf(x.Sentence))
            .Select(x => x.Sentence);

        return string.Join(" ", selected);
    }

    private static Dictionary<string, int> GetWordFrequency(string text)
    {
        return WordRegex().Matches(text.ToLowerInvariant())
            .GroupBy(m => m.Value)
            .ToDictionary(g => g.Key, g => g.Count());
    }

    private static double ScoreSentence(string sentence, Dictionary<string, int> wordFrequency)
    {
        var words = WordRegex().Matches(sentence.ToLowerInvariant());
        if (words.Count == 0) return 0;

        return words.Sum(w => wordFrequency.GetValueOrDefault(w.Value, 0)) / (double)words.Count;
    }

    [GeneratedRegex(@"[^.!?]*[.!?]+", RegexOptions.Compiled)]
    private static partial Regex SentenceRegex();

    [GeneratedRegex(@"\b\w{3,}\b", RegexOptions.Compiled)]
    private static partial Regex WordRegex();
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController : ControllerBase
{
    private readonly IDocumentSummarizer _summarizer;

    public SummarizeController(IDocumentSummarizer summarizer)
    {
        _summarizer = summarizer;
    }

    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Text))
            return BadRequest(new { error = "Text is required." });

        var summary = _summarizer.Summarize(request.Text, request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalLength = request.Text.Length,
            SummaryLength = summary.Length
        });
    }
}

